static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    LogSoftmaxCustomTilingData tiling;
    const uint32_t totalLength =
        static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());
    // input is 2D: batch_size x cols
    const uint32_t batchSize = context->GetInputShape(0)->GetOriginShape().GetDim(0);
    const uint32_t cols = context->GetInputShape(0)->GetOriginShape().GetDim(1);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *dim = attrs->GetAttrPointer<int64_t>(0);
    // dim ignored; we assume dim = 1

    // UB: need 3 tile buffers (input, temp, output) of floats
    uint32_t maxTile = UB_BUDGET_BYTES / (3 * 4);  // 3 floats per element
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    // tileLength: columns per tile, not larger than cols
    uint32_t tileLen = (maxTile < cols) ? maxTile : cols;
    if (tileLen > cols) tileLen = cols;
    // align down to ALIGN_ELEMS but keep at least 1 element
    uint32_t alignedTile = AlignDown(tileLen, ALIGN_ELEMS);
    if (alignedTile == 0) alignedTile = tileLen;
    tileLen = alignedTile;

    // block dimension: use up to 24 blocks, at least 1
    uint32_t blockDim = batchSize;
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

